<?php
namespace WCSA\Auth; defined('ABSPATH') || exit; use WCSA\Options; use WCSA\Support\Helpers;
final class OtpStore{ private static function ok(string $m):string{return 'wcsa_otp_'.md5($m);} private static function mk(string $m):string{return 'wcsa_send_m_'.md5($m);} private static function ik(string $ip):string{return 'wcsa_send_ip_'.md5($ip);} private static function rk(string $t):string{return 'wcsa_reg_'.md5($t);} public static function canSend(string $m,string $ip):array{ if((int)get_transient(self::mk($m))>=(int)Options::get('otp_max_send_10min',3))return ['ok'=>false,'message'=>'برای این شماره درخواست زیادی ثبت شده است. چند دقیقه بعد تلاش کنید.']; if((int)get_transient(self::ik($ip))>=(int)Options::get('ip_max_send_10min',10))return ['ok'=>false,'message'=>'تعداد درخواست‌ها از این اتصال بیش از حد مجاز است.']; $old=get_transient(self::ok($m)); if(is_array($old)&&!empty($old['created'])&&time()-(int)$old['created']<(int)Options::get('otp_resend_delay',60))return ['ok'=>false,'message'=>'برای ارسال مجدد کمی صبر کنید.']; return ['ok'=>true,'message'=>''];} public static function bumpSend(string $m,string $ip):void{set_transient(self::mk($m),(int)get_transient(self::mk($m))+1,10*MINUTE_IN_SECONDS);set_transient(self::ik($ip),(int)get_transient(self::ik($ip))+1,10*MINUTE_IN_SECONDS);} public static function store(string $m,string $otp):void{$ttl=(int)Options::get('otp_ttl',120);set_transient(self::ok($m),['hash'=>Helpers::otpHash($otp,$m),'created'=>time(),'attempts'=>0,'ttl'=>$ttl],$ttl);} public static function verify(string $m,string $otp):array{$p=get_transient(self::ok($m)); if(!is_array($p)||empty($p['hash']))return ['ok'=>false,'message'=>'کد منقضی شده است. دوباره درخواست دهید.']; if((int)($p['attempts']??0)>=(int)Options::get('otp_max_verify',5)){delete_transient(self::ok($m)); return ['ok'=>false,'message'=>'تعداد تلاش بیش از حد مجاز است. دوباره درخواست دهید.'];} $p['attempts']=(int)$p['attempts']+1; set_transient(self::ok($m),$p,max(30,(int)($p['ttl']??120))); if(!hash_equals((string)$p['hash'],Helpers::otpHash($otp,$m)))return ['ok'=>false,'message'=>'کد تایید صحیح نیست.']; delete_transient(self::ok($m)); return ['ok'=>true,'message'=>''];} public static function issueRegisterToken(string $m):string{$t=wp_generate_password(40,false,false);set_transient(self::rk($t),['mobile'=>$m],10*MINUTE_IN_SECONDS);return $t;} public static function consumeRegisterToken(string $t):?string{$k=self::rk($t);$p=get_transient($k); if(is_array($p)&&!empty($p['mobile'])){delete_transient($k);return (string)$p['mobile'];}return null;}}
